    results = searcher.search(query, top_k=top_k)

    filtered_results = []
    for result in results:
        passes_all_filters = True
        for field_name, condition in metadata_filters.items():
            operator, value = next(iter(condition.items()))
            result_value = result.metadata.get(field_name)

            if operator == "==":
                if result_value != value:
                    passes_all_filters = False
                    break
            elif operator == "!=":
                if result_value == value:
                    passes_all_filters = False
                    break
            elif operator == ">":
                if result_value <= value:
                    passes_all_filters = False
                    break
            elif operator == ">=":
                if result_value < value:
                    passes_all_filters = False
                    break
            elif operator == "<":
                if result_value >= value:
                    passes_all_filters = False
                    break
            elif operator == "<=":
                if result_value > value:
                    passes_all_filters = False
                    break
            else:
                passes_all_filters = False
                break

        if passes_all_filters:
            filtered_results.append(result)

    return filtered_results[:top_k]

from typing import List, Dict, Any
from leann.api import PassageManager
from pathlib import Path
import json

def find_passages_by_text_pattern(
    index_path: str,
    pattern: str,
    case_sensitive: bool = False
) -> List[Dict[str, Any]]:
    """Find all passages in an index whose text contains a specified pattern."""
    if not pattern:
        raise ValueError("pattern cannot be empty")

    # Construct metadata file path
    index_file = Path(index_path)
    meta_file = index_file.parent / f"{index_file.stem}.meta.json"

    if not meta_file.exists():
        raise FileNotFoundError(f"Index metadata file not found at {meta_file}")

    # Initialize PassageManager and retrieve passages
    pm = PassageManager(index_path)

    result = []
    for passage in pm:
        text = passage.get('text', '')
        if case_sensitive:
            if pattern in text:
                result.append(passage)
        else:
            if pattern.lower() in text.lower():
                result.append(passage)

    return result

from typing import List, Dict, Any
from leann.api import LeannBuilder
from pathlib import Path

def build_index_with_metadata_validation(
    documents: List[Dict[str, Any]],
    index_path: str,
    required_metadata_fields: List[str] = None,
    backend_name: str = "hnsw"
) -> str:
    """Build a LEANN index with validation of required metadata fields."""
    if not documents:
        raise ValueError("missing required metadata fields")

    if required_metadata_fields is not None:
        for doc in documents:
            metadata = doc['metadata']
            for field in required_metadata_fields:
                if field not in metadata:
                    raise ValueError("missing required metadata fields")

    index_path_obj = Path(index_path)
    index_path_obj.parent.mkdir(parents=True, exist_ok=True)

    builder = LeannBuilder(backend_name=backend_name)
    for doc in documents:
        builder.add_text(doc['text'], metadata=doc['metadata'])
    builder.build_index(str(index_path_obj))

    return index_path

