def get_passages_by_text_contains(
    index_path: str,
    search_text: str,
    case_sensitive: bool = False
) -> List[Dict[str, Any]]:
    """Retrieve passages from an index whose text contains a specific substring."""
    if not Path(index_path).exists():
        raise FileNotFoundError(f"Index file not found: {index_path}")
    if not search_text:
        raise ValueError("search_text cannot be empty")

    pm = PassageManager(index_path)
    matching_passages = []

    for passage in pm.passages():
        passage_text = passage['text']
        if case_sensitive:
            if search_text in passage_text:
                matching_passages.append(passage)
        else:
            if search_text.lower() in passage_text.lower():
                matching_passages.append(passage)

    return matching_passages

from typing import List, Dict, Any
from leann.api import LeannSearcher, SearchResult

def search_with_score_normalization(
    index_path: str,
    query: str,
    normalize_to_range: tuple = (0.0, 1.0),
    top_k: int = 10
) -> List[SearchResult]:
    """Search in an index and normalize result scores to a specified range."""
    min_range, max_range = normalize_to_range
    if min_range >= max_range:
        raise ValueError("min must be less than max")

    try:
        searcher = LeannSearcher(index_path)
    except FileNotFoundError:
        raise FileNotFoundError(f"Index file not found: {index_path}")

    results = searcher.search(query, top_k=top_k)

    scores = [result.score for result in results]

    if not scores:
        return []

    s_min = min(scores)
    s_max = max(scores)

    if s_min == s_max:
        normalized_score = (min_range + max_range) / 2
    else:
        normalized_scores = []
        for score in scores:
            normalized = min_range + (score - s_min) * (max_range - min_range) / (s_max - s_min)
            normalized_scores.append(normalized)

        # Assign normalized scores to results
        for i, result in enumerate(results):
            result.score = normalized_scores[i]

    return results
